# scripts/detect-architecture-drift.py
import ast, json, pathlib, sys, yaml

BASELINE_PATH = pathlib.Path("architecture.json")
SRC_DIRS = [pathlib.Path("src"), pathlib.Path("app"), pathlib.Path("integrations")]
PROMPTS_DIR = pathlib.Path("prompts")


def load_baseline() -> dict:
    with open(BASELINE_PATH) as f:
        return json.load(f)


def scan_model_ids(src_dirs) -> set[str]:
    """Return all model ID string literals found in Python source files."""
    found = set()
    for d in src_dirs:
        if not d.exists():
            continue
        for path in d.rglob("*.py"):
            tree = ast.parse(path.read_text())
            for node in ast.walk(tree):
                if isinstance(node, ast.Constant) and isinstance(node.value, str):
                    v = node.value
                    if v.startswith("claude-") and len(v) > 8:
                        found.add(v)
    return found


def scan_inline_prompts(src_dirs) -> list[tuple[str, int]]:
    """Return (file, line) for any string literal > 150 chars that looks like a system prompt."""
    violations = []
    for d in src_dirs:
        if not d.exists():
            continue
        for path in d.rglob("*.py"):
            tree = ast.parse(path.read_text())
            for node in ast.walk(tree):
                if isinstance(node, ast.Constant) and isinstance(node.value, str):
                    v = node.value
                    if len(v) > 150 and any(kw in v.lower() for kw in
                            ("you are", "your role", "do not", "never reveal",
                             "your task is", "as an assistant")):
                        violations.append((str(path), node.lineno))
    return violations


def scan_direct_client_constructions(src_dirs, factory_modules) -> list[tuple[str, int]]:
    """Return (file, line) for any direct anthropic.Anthropic() outside the factory."""
    factory_paths = {pathlib.Path(m) for m in factory_modules}
    violations = []
    for d in src_dirs:
        if not d.exists():
            continue
        for path in d.rglob("*.py"):
            if path in factory_paths:
                continue  # factory itself is exempt
            tree = ast.parse(path.read_text())
            for node in ast.walk(tree):
                if isinstance(node, ast.Call):
                    func = node.func
                    # Match anthropic.Anthropic() or Anthropic()
                    if isinstance(func, ast.Attribute) and func.attr == "Anthropic":
                        violations.append((str(path), node.lineno))
                    elif isinstance(func, ast.Name) and func.id == "Anthropic":
                        violations.append((str(path), node.lineno))
    return violations


def scan_safety_baseline_versions(prompts_dir, current_version) -> list[tuple[str, str]]:
    """Return (template_path, version_found) for templates on outdated safety baselines."""
    outdated = []
    if not prompts_dir.exists():
        return outdated
    for path in prompts_dir.rglob("*.yml"):
        with open(path) as f:
            template = yaml.safe_load(f)
        version = template.get("safety_baseline_version", "MISSING")
        if version != current_version:
            outdated.append((str(path), version))
    return outdated


def detect_drift(baseline: dict) -> dict:
    drift = {}

    # Model drift
    live_models = scan_model_ids(SRC_DIRS)
    approved = set(baseline["approved_models"])
    unapproved = live_models - approved
    if unapproved:
        drift["unapproved_models"] = sorted(unapproved)

    # Inline prompt drift
    inline = scan_inline_prompts(SRC_DIRS)
    if inline:
        drift["inline_prompts"] = [{"file": f, "line": l} for f, l in inline]

    # Direct client construction drift
    direct = scan_direct_client_constructions(SRC_DIRS, baseline["client_factory_modules"])
    if direct:
        drift["direct_client_constructions"] = [{"file": f, "line": l} for f, l in direct]

    # Safety baseline drift
    outdated = scan_safety_baseline_versions(
        PROMPTS_DIR, baseline["safety_baseline_current_version"]
    )
    if outdated:
        drift["outdated_safety_baselines"] = [
            {"template": t, "version": v} for t, v in outdated
        ]

    return drift


if __name__ == "__main__":
    baseline = load_baseline()
    drift = detect_drift(baseline)
    if drift:
        print(json.dumps({"status": "drift_detected", "drift": drift}, indent=2))
        sys.exit(1)
    else:
        print(json.dumps({"status": "clean", "baseline": baseline["snapshot_date"]}))
        sys.exit(0)
